import{_ as e,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"10. Anti Discrimination","description":"","frontmatter":{"title":"10. Anti Discrimination","eba":"Nurses and Midwives 2024-2028","topics":["flexible-work","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/nurses-midwives/preliminary/10-anti-discrimination.md","filePath":"ebas/nurses-midwives/preliminary/10-anti-discrimination.md"}'),r={name:"ebas/nurses-midwives/preliminary/10-anti-discrimination.md"};function o(s,i,c,l,m,d){return t(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="_10-anti-discrimination" tabindex="-1">10. Anti Discrimination <a class="header-anchor" href="#_10-anti-discrimination" aria-label="Permalink to &quot;10. Anti Discrimination&quot;">​</a></h1><p><strong>10.1</strong> Those covered by this Agreement respect and value the diversity of the work force and protection against unfair treatment and discrimination on the basis of race, colour, sex, sexual orientation, breastfeeding, gender identity, intersex status, an experience of family or domestic violence, age, physical or mental disability, marital status, family or carer responsibilities, pregnancy, religion, political opinion, national extraction or social origin.</p><p><strong>10.2</strong> Those covered by the Agreement must make every reasonable endeavour to ensure that neither the Agreement provisions nor their operation are directly or indirectly unlawfully discriminatory in their effects.</p><p><strong>10.3</strong> Nothing in this clause is taken to affect:</p><p><strong>(a)</strong> any different treatment (or treatment having different effects) which is specifically exempted under Commonwealth or State anti-discrimination legislation;</p><p><strong>(b)</strong> an Employee, Employer or registered organisation, pursuing matters of discrimination in any State or Federal jurisdiction, including any application to the Australian Human Rights Commission; or</p><p><strong>(c)</strong> the exemptions in section 351(2) of the Act.</p><p>Plain language terms: discrimination, equal opportunity, race, disability.</p>',8)])])}const u=e(r,[["render",o]]);export{g as __pageData,u as default};
